async function getFixtureIds(request: import('@playwright/test').APIRequestContext): Promise<{
	nodeId: string;
	projectId: string;
	nodeName: string;
	projectName: string;
	projectPath: string;
}> {
	const nodeResp = await request.post('/graphql', {
		data: { query: '{ nodeInfo { id name } }' }
