func (s *ServerState) GetRunBundleFileGraphQL(id, path string) (*ddxgraphql.RunBundleFileContent, bool) {
	bundleRoot, _, ok := s.runBundleRoot(id)
	if !ok {
		return nil, false
	}
	return readRunBundleFile(bundleRoot, path)
}

